#include <iostream>
#include <list>
using namespace std;
list<int> people;
int main()
{
    int n,m;
    cin>>n>>m;
    for(int i=1;i<=n;i++)
    {
        people.push_back(i);
    }
    list<int>::iterator it=people.begin();
    list<int>::iterator loc;
    int num=1;
    while(!people.empty())
    {
        if(num==m)
        {
            cout<<*it<<' ';
            loc=it;
            it++;
            people.erase(loc);
            num=1;
        }
        else
        {
            num++;
            it++;
        }
        if(it==people.end())
        {
            it=people.begin();
        }
    }
    return 0;
}
